mapper.select:
select a.*,
p.id as permissionId
from iam_api a
inner join iam_permission p on a.id = p.resource_id


        AND a.application_id = #{qry.applicationId}


        AND a.category_id = #{qry.categoryId}


        AND a.auth_type = #{qry.authType}

    AND p.type = 'SER_API'
    AND a.is_deleted = 0
